import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const formatPrice = (p) => (p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—');

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  // Use state keys that match what handleFilterChange expects
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    propertyType: searchParams.get('propertyType') || '', 
    minPrice: searchParams.get('minPrice') || '',
    maxPrice: searchParams.get('maxPrice') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parkingSpaces: searchParams.get('parkingSpaces') || '',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);

  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);

    try {
      // Create exact API mapping
      const apiParams = {
        page: currentPage,
        per_page: 10, // Explicitly tell backend 10 per page
        state: currentFilters.state,
        suburb: currentFilters.suburb,
        postcode: currentFilters.postcode,
        property_type: currentFilters.propertyType,
        min_price: currentFilters.minPrice,
        max_price: currentFilters.maxPrice,
        bedrooms: currentFilters.bedrooms,
        bathrooms: currentFilters.bathrooms,
        parking_spaces: currentFilters.parkingSpaces,
      };

      // CRITICAL: Clean params to ensure only non-empty values are sent
      const finalParams = {};
      Object.keys(apiParams).forEach((key) => {
        const val = apiParams[key];
        if (val !== '' && val !== null && val !== undefined) {
          finalParams[key] = val;
        }
      });

      const response = await searchRentals(finalParams);
      setResults(response);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);
      
      const urlParams = {};
      Object.entries(filters).forEach(([k, v]) => { if (v) urlParams[k] = v; });
      if (page > 1) urlParams.page = page;
      setSearchParams(urlParams, { replace: true });
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1); // Crucial: Always go back to page 1 on new filter
  };

  const rentals = results?.data || [];
  const totalPages = results?.pagination?.lastPage || 1;
  const totalResults = results?.pagination?.total || 0;

  return (
    <div className="search-page">
      <aside className="search-page__sidebar">
        <div className="filter-panel">
          <h3>Filter Rentals</h3>
          
          <div className="filter-group">
            <label>State</label>
            <select value={filters.state} onChange={(e) => handleFilterChange('state', e.target.value)}>
              <option value="">All States</option>
              {states.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label>Type</label>
            <select value={filters.propertyType} onChange={(e) => handleFilterChange('propertyType', e.target.value)}>
              <option value="">All Types</option>
              {propertyTypes.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label>Rent Range</label>
            <div className="filter-row">
              <input type="number" placeholder="Min" value={filters.minPrice} onChange={(e) => handleFilterChange('minPrice', e.target.value)} />
              <input type="number" placeholder="Max" value={filters.maxPrice} onChange={(e) => handleFilterChange('maxPrice', e.target.value)} />
            </div>
          </div>

          <div className="filter-group">
            <label>Bedrooms</label>
            <input type="number" value={filters.bedrooms} onChange={(e) => handleFilterChange('bedrooms', e.target.value)} />
          </div>

          <div className="filter-group">
            <label>Bathrooms</label>
            <input type="number" value={filters.bathrooms} onChange={(e) => handleFilterChange('bathrooms', e.target.value)} />
          </div>

          <div className="filter-group">
            <label>Parking</label>
            <input type="number" value={filters.parkingSpaces} onChange={(e) => handleFilterChange('parkingSpaces', e.target.value)} />
          </div>
        </div>
      </aside>

      <main className="search-page__results">
        <h2>{loading ? 'Updating...' : `${totalResults} Results`}</h2>

        <div className="results-table-container">
          <table className="results-table">
            <thead>
              <tr>
                <th>Address</th>
                <th>State</th>
                <th>Type</th>
                <th>Bed</th>
                <th>Bath</th>
                <th>Park</th>
                <th>Price</th>
              </tr>
            </thead>
            <tbody>
              {!loading && rentals.map((r) => (
                <tr key={r.id} onClick={() => navigate(`/rental/${r.id}`)}>
                  <td>{r.title} <br/><small>{r.suburb}</small></td>
                  <td>{r.state}</td>
                  <td>{r.propertyType}</td>
                  <td>{r.bedrooms}</td>
                  <td>{r.bathrooms}</td>
                  <td>{r.parkingSpaces}</td>
                  <td>{formatPrice(r.rent)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {!loading && totalPages > 1 && (
          <Pagination
            page={page}
            totalPages={totalPages}
            onPageChange={(p) => setPage(p)}
          />
        )}
      </main>
    </div>
  );
};

export default SearchPage;
